import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ArrowLeft, Briefcase, Calendar, Award } from 'lucide-react';

const ExperienceDetail = () => {
  const { experienceId } = useParams();
  const navigate = useNavigate();

  const experiences = [
    {
      id: 0,
      company: "DigitalBee Labs",
      role: "Trainer Software Engineer",
      period: "2024 - Present",
      description: "Currently training and mentoring junior developers in modern web technologies and software engineering best practices. Leading workshops and code reviews.",
      longDescription: "As a Trainer Software Engineer at DigitalBee Labs, I am responsible for developing and delivering training programs to junior developers. I focus on imparting knowledge of modern web development frameworks, clean code principles, and software engineering best practices. My role includes conducting code reviews, mentoring sessions, and creating comprehensive training materials.",
      skills: ["React", "JavaScript", "Teaching", "Mentoring", "Web Development", "Node.js"],
      achievements: [
        "Trained 15+ junior developers in React and modern JavaScript",
        "Developed comprehensive training curriculum",
        "Improved code quality through mentorship and code reviews",
        "Created reusable learning materials and documentation"
      ]
    },
    {
      id: 1,
      company: "TechNexus Solutions",
      role: "Senior Full-Stack Developer",
      period: "2021 - Present",
      description: "Leading a squad of 8 developers in migrating a legacy monolith into a serverless microservices architecture using AWS and React.",
      longDescription: "At TechNexus Solutions, I led the architectural transformation of a legacy monolithic application into a modern serverless microservices architecture. I managed a team of 8 developers and coordinated with cross-functional teams to ensure smooth migration and deployment on AWS infrastructure.",
      skills: ["React", "AWS", "Node.js", "Docker", "Kubernetes", "Microservices"],
      achievements: [
        "Successfully migrated legacy system reducing deployment time by 60%",
        "Managed team of 8 developers across multiple time zones",
        "Implemented CI/CD pipeline reducing production issues by 40%",
        "Reduced infrastructure costs by 35% through AWS optimization"
      ]
    },
    {
      id: 2,
      company: "Innovate Digital",
      role: "Frontend Engineer",
      period: "2019 - 2021",
      description: "Spearheaded the redesign of the core dashboard, increasing user engagement by 35% and improving lighthouse scores by 40 points.",
      longDescription: "During my time at Innovate Digital, I led the complete redesign of the company's flagship dashboard. The project involved optimizing performance, improving UI/UX, and implementing modern frontend technologies. The redesign resulted in significantly improved metrics and user satisfaction.",
      skills: ["Vue.js", "Tailwind CSS", "TypeScript", "Jest", "Webpack"],
      achievements: [
        "Redesigned dashboard increasing user engagement by 35%",
        "Improved Lighthouse performance score by 40 points",
        "Reduced initial load time from 4.2s to 1.8s",
        "Implemented comprehensive test coverage (90%+)"
      ]
    },
    {
      id: 3,
      company: "Launchpad Startups",
      role: "Junior Web Developer",
      period: "2018 - 2019",
      description: "Built responsive landing pages and internal admin tools. Optimized database queries for high-traffic real-time features.",
      longDescription: "As a Junior Web Developer at Launchpad Startups, I contributed to various projects including building responsive websites and internal tools. I gained hands-on experience with database optimization and learned the importance of efficient query design for high-traffic applications.",
      skills: ["PHP", "JavaScript", "MySQL", "Sass", "HTML/CSS"],
      achievements: [
        "Built 5+ responsive landing pages with 98%+ browser compatibility",
        "Optimized database queries improving response time by 55%",
        "Developed internal admin dashboard used by 50+ employees",
        "Mentored by senior developers learning industry best practices"
      ]
    }
  ];

  const experience = experiences.find(exp => exp.id === parseInt(experienceId));

  if (!experience) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-darkBg flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-3xl font-bold mb-4">Experience not found</h1>
          <button
            onClick={() => navigate('/')}
            className="px-6 py-2 bg-primary text-white rounded-lg hover:bg-primary/90"
          >
            Back to Home
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 dark:bg-darkBg">
      {/* Navigation Bar */}
      <nav className="sticky top-0 z-50 bg-white/95 dark:bg-darkBg/95 backdrop-blur-md border-b border-slate-200 dark:border-slate-800">
        <div className="container mx-auto px-6 py-4">
          <button
            onClick={() => navigate('/')}
            className="flex items-center gap-2 text-primary hover:gap-3 transition-all"
          >
            <ArrowLeft size={20} />
            <span className="font-semibold">Back to Home</span>
          </button>
        </div>
      </nav>

      {/* Main Content */}
      <div className="container mx-auto px-6 py-20">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          {/* Header Section */}
          <div className="mb-12">
            <div className="flex items-start justify-between mb-6">
              <div>
                <h1 className="text-5xl font-bold mb-2">{experience.role}</h1>
                <p className="text-2xl text-primary font-semibold">{experience.company}</p>
              </div>
              <div className="glass p-6 rounded-2xl text-right">
                <div className="flex items-center justify-end gap-2 mb-2">
                  <Calendar size={20} className="text-primary" />
                  <span className="text-lg font-semibold">{experience.period}</span>
                </div>
              </div>
            </div>

            <div className="prose dark:prose-invert max-w-none">
              <p className="text-xl text-slate-700 dark:text-slate-300 leading-relaxed">
                {experience.longDescription}
              </p>
            </div>
          </div>

          {/* Description Section */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.1 }}
            className="glass p-8 rounded-3xl mb-12"
          >
            <h2 className="text-2xl font-bold mb-4 flex items-center gap-2">
              <Briefcase size={24} className="text-primary" />
              Overview
            </h2>
            <p className="text-slate-700 dark:text-slate-300 text-lg leading-relaxed">
              {experience.description}
            </p>
          </motion.div>

          {/* Skills Section */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.2 }}
            className="mb-12"
          >
            <h2 className="text-2xl font-bold mb-6">Technologies & Skills</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {experience.skills.map((skill, index) => (
                <motion.div
                  key={skill}
                  initial={{ opacity: 0, scale: 0.8 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: 0.2 + index * 0.05 }}
                  className="glass p-4 rounded-xl border border-primary/10 hover:border-primary/30 transition-all"
                >
                  <p className="text-center font-semibold text-primary">{skill}</p>
                </motion.div>
              ))}
            </div>
          </motion.div>

          {/* Achievements Section */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 0.3 }}
          >
            <h2 className="text-2xl font-bold mb-6 flex items-center gap-2">
              <Award size={24} className="text-primary" />
              Key Achievements
            </h2>
            <div className="space-y-4">
              {experience.achievements.map((achievement, index) => (
                <motion.div
                  key={index}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.3 + index * 0.1 }}
                  className="glass p-6 rounded-2xl border-l-4 border-primary"
                >
                  <p className="text-slate-700 dark:text-slate-300 text-lg">
                    {achievement}
                  </p>
                </motion.div>
              ))}
            </div>
          </motion.div>
        </motion.div>
      </div>
    </div>
  );
};

export default ExperienceDetail;
